-- FIFA World Cup 2026 Prediction League fixture table
-- Store kickoff_at as UTC timestamptz. For UI, display it in Asia/Dhaka.

CREATE TABLE IF NOT EXISTS matches (
  id SERIAL PRIMARY KEY,
  match_no INT UNIQUE,
  team_a VARCHAR(100),
  team_b VARCHAR(100),
  team_a_placeholder VARCHAR(150),
  team_b_placeholder VARCHAR(150),
  match_date DATE NOT NULL,
  match_time TIME NOT NULL,
  kickoff_at TIMESTAMPTZ NOT NULL,
  stage VARCHAR(30) NOT NULL,
  round_name VARCHAR(50),
  group_name VARCHAR(50),
  venue VARCHAR(150),
  status VARCHAR(20) DEFAULT 'upcoming',
  actual_team_a_score INT,
  actual_team_b_score INT,
  actual_qualifier VARCHAR(100),
  created_at TIMESTAMP DEFAULT NOW(),
  updated_at TIMESTAMP DEFAULT NOW()
);

